UPDATE public.blog_articles SET title_en = 'Peri-urban Market Gardening in Ziguinchor: Women on the Front Line of Food Security', excerpt_en = 'In the peripheral neighborhoods of Ziguinchor — Kandé, Lyndiane, Belfort — hundreds of women cultivate vegetables and condiments on small irrigated plots. A discreet but essential link in local food, which is becoming more professional under the cooperative''s influence.' WHERE id = '9bafe0e8-63bb-47c2-8daa-1fe206cc958a';
UPDATE public.blog_articles SET title_en = 'Cashew: Casamance''s Gold Facing Local Processing Challenges', excerpt_en = 'Senegal is the 5th largest producer of cashew nuts in the world and Casamance produces over 80% of it. However, more than 95% of raw nuts are exported without processing. A huge missed opportunity that the cooperative intends to correct.' WHERE id = '7552523d-ca5f-4c71-b7ca-b05bce379bcb';
UPDATE public.blog_articles SET title_en = 'Rice Farming in Casamance: Valleys Under Pressure from Salinization', excerpt_en = 'The alluvial plains of Casamance have earned the region its reputation as Senegal''s « rice bowl ». But salt intrusion, accelerated by droughts and deforestation, eats away hundreds of hectares of rice fields every year. An existential challenge for rural communities.' WHERE id = '940ecc9f-19aa-4aa1-9a74-da0dd0acaa5f';
UPDATE public.blog_articles SET title_en = 'Sesame: The Discreet Crop Silently Transforming Incomes in Casamance', excerpt_en = 'Less publicized compared to mango or cashew, sesame is experiencing remarkable expansion in the departments of Sédhiou and Kolda. Its low input requirement, ease of conservation, and strong Asian demand make it a credible alternative for small producers.' WHERE id = '5bc17923-14e2-4617-acdd-d37c4ceaa8c4';
UPDATE public.blog_articles SET title_en = 'Casamance Bananas Regain Their Market Against Imports', excerpt_en = 'Long competed against by bananas imported from Ecuador and Ivory Coast, local Casamance bananas are progressively regaining urban markets thanks to their strong taste and short-circuit argument. The Santhiaba-Manjaque area concentrates the best orchards.' WHERE id = 'f4e4a747-d738-4cc5-a77a-07b61a841760';
UPDATE public.blog_articles SET title_en = 'Agroforestry in Casamance: Reconciling Agricultural Productivity and Forest Biodiversity', excerpt_en = 'Casamance has lost more than 60% of its forest cover in 50 years. Faced with this galloping deforestation, producers from the cooperative are experimenting with agroforestry — cultivating under and around trees — to restore ecosystems while maintaining their incomes.' WHERE id = '3af58335-da1a-430b-bc04-9b04be3a8218';
UPDATE public.blog_articles SET title_en = 'Citrus in Casamance: A High-Potential Sector Seeking Outlets', excerpt_en = 'Oranges, clementines, grapefruits, lemons — Casamance produces a great diversity of citrus fruits, mainly in the Oussouye area and the town of Niaguis. Despite recognized organoleptic quality, the sector struggles to organize against Moroccan imports.' WHERE id = 'eb02f470-a539-4d76-a582-031426375d48';
UPDATE public.blog_articles SET title_en = 'Post-Harvest Losses: How the Cooperative Reduced Mango Waste by 30% in Two Years', excerpt_en = 'In 2022, nearly a third of mangoes harvested in Casamance never reached the final consumer — a considerable economic and human waste. Through an equipment and training program, the cooperative managed to reduce these losses to 20% in 2024.' WHERE id = '833f60ef-854f-43bb-8481-086e46859cce';
UPDATE public.blog_articles SET title_en = 'Casamance Kent Mango: Keys to a High-Performing Export Sector', excerpt_en = 'With over 60% of national production, Casamance stands out as Senegal''s leading mango basin. The Kent variety, highly prized in European markets, alone accounts for 70% of the region''s exported volumes. How is the cooperative structuring this sector to maximize value?' WHERE id = 'a65f1421-d294-4778-93da-74bd3caf0833';
UPDATE public.projects SET title_en = 'Mango Cold Storage Platform — Bignona & Oussouye', description_en = 'Construction of two cold storage warehouses (100 m³ each) powered by solar panels in the Bignona and Oussouye areas. Objective: reduce post-harvest mango losses from 33% to 15% by 2026 by maintaining the cold chain between harvest and export loading.' WHERE id = '730e01f7-f7e3-4e46-962f-77ae8d85bc6a';
UPDATE public.projects SET title_en = 'Semi-Industrial Cashew Processing Unit — Ziguinchor', description_en = 'Feasibility study and financial modeling for a processing unit of 500 tons/year of raw cashew nuts into shelled kernels. The objective is to multiply the local added value of cashew by 8 and create 80 permanent jobs, 60% of which for women.' WHERE id = '77a73dd0-0830-4ed8-a95a-ea20ab96835b';
UPDATE public.projects SET title_en = 'Support for Women''s Market Gardening — 12 Groups in Ziguinchor', description_en = 'Strengthening 12 peri-urban women''s market gardening groups through the installation of solar irrigation pumps, training in composting and stock management, and setting up a 5M FCFA guarantee fund for microcredit access. Target: increase annual income by 35%.' WHERE id = '5d81d8a3-16f0-4ae4-bd59-a5290500337a';
UPDATE public.projects SET title_en = 'Agroforestry Reforestation — 50,000 Trees on 600 ha in Casamance', description_en = 'Agroforestry planting program combining fruit species (mango, cashew) and local forest species on the cooperative members'' plots. Aims to restore forest cover, improve soil fertility, and diversify agricultural incomes.' WHERE id = '922e8fd2-f028-4d43-9540-e5e9885b84a2';
UPDATE public.projects SET title_en = 'Development of GMO-Free Sesame Sector — Export to Japan & Korea', description_en = 'Structuring a group of 80 sesame producers in the Sédhiou department around a « GMO-free / synthetic pesticide-free » specification meeting the requirements of Asian buyers. 3-year contracting program with an exporter for 200 tons/year.' WHERE id = 'b0ca7a43-e4df-4615-84a2-7a32f00021e9';
UPDATE public.projects SET title_en = 'Artisanal Citrus Pressing Workshops — Oussouye & Cap Skirring', description_en = 'Installation of 5 artisanal orange, grapefruit, and lemon pressing workshops in the Oussouye area, aiming to provide premium fresh juice to hotels and tourist restaurants in Cap Skirring and Ziguinchor.' WHERE id = 'f4821b39-277b-4a77-af31-6fdb78d785c3';
UPDATE public.projects SET title_en = 'Rehabilitation of 45 km of Anti-Salt Dikes — Casamance Rice Farming', description_en = 'Rehabilitation of 45 km of saline intrusion dikes in the communes of Kabrousse, Nyassia, and Diouloulou. The project aims to recover 1,200 ha of rice fields abandoned since the 1980-90 droughts. 620 beneficiary rice-farming families.' WHERE id = '85d3306f-882a-462d-acb3-e89999030468';
UPDATE public.projects SET title_en = 'CRPAZ Digital Platform — Integrated Cooperative Management', description_en = 'Deployment of a digital management system covering producers, orchards, stocks, orders, finances, and invoicing. Includes a public online sales portal, market price transparency dashboard, and reporting tools.' WHERE id = 'f3f3f123-0c4a-49f4-b10f-ed46e1ec1c2b';
UPDATE public.projects SET title_en = 'GlobalG.A.P Cashew Certification — Sédhiou-Ziguinchor Zone', description_en = 'Support program for 120 cashew producers towards dual GlobalG.A.P and Rainforest Alliance certification. Certification opens access to premium European and Japanese buyers with a price differential estimated at +18% over the spot market.' WHERE id = '9dadb586-670e-4560-a863-9308daeee1b2';
UPDATE public.projects SET title_en = 'Casamance Farmers'' School — Mango & Cashew GAP', description_en = '3-year continuous training program focused on Good Agricultural Practices (GAP) for the mango and cashew sectors. Modules on integrated pest management, farm record keeping, and simplified financial management. 240 certified producers.' WHERE id = '3e176836-9247-479f-8d0b-c8783e4d8dc9';
